function DrawWordCloud() {
  const { WordCloud } = components;
  const dimensionField = "dimension_column";
  const cloudData = data.map((item) => ({
    ...item,
    name: item[dimensionField],
    value: 1
  }));
  const config = {
    data: cloudData,
    wordField: "name",
    weightField: "value",
    color: "rgba(76, 132, 238, 1)",
    interactions: [{ type: "element-active" }]
  };
  return <div><WordCloud {...config} /></div>;
}
